#include &lt;openssl/ssl.h&gt;
#include &lt;openssl/err.h&gt;
#include &lt;sys/epoll.h&gt;

// We must wrap SSL_read in a state-aware function
int secure_nonblocking_read(SSL *ssl, int epoll_fd, int client_fd, char *buffer, int len) {
    int bytes = SSL_read(ssl, buffer, len);

    if (bytes <= 0) {
        int err = SSL_get_error(ssl, bytes);
        struct epoll_event ev;
        ev.data.fd = client_fd;

        if (err == SSL_ERROR_WANT_READ) {
            // OpenSSL needs more data from the network to proceed.
            // We must configure epoll to wake us up when the socket is READABLE.
            ev.events = EPOLLIN | EPOLLET;
            epoll_ctl(epoll_fd, EPOLL_CTL_MOD, client_fd, &ev);
            return 0; // Tell application to wait

        } else if (err == SSL_ERROR_WANT_WRITE) {
            // Paradox: OpenSSL needs to write to the network during our read!
            // We must configure epoll to wake us up when the socket is WRITABLE.
            ev.events = EPOLLOUT | EPOLLET;
            epoll_ctl(epoll_fd, EPOLL_CTL_MOD, client_fd, &ev);
            return 0; // Tell application to wait

        } else {
            // A fatal cryptographic or network error occurred.
            ERR_print_errors_fp(stderr);
            return -1;
        }
    }

    return bytes; // Successfully decrypted payload
}

