// 1. VULNERABLE: Standard strcmp/memcmp pattern
// Returns instantly on the first mismatch. Leaks exact prefix matches via timing.
int vulnerable_compare(const uint8_t *secret, const uint8_t *guess, size_t len) {
    for (size_t i = 0; i < len; i++) {
        if (secret[i] != guess[i]) {
            return 0; // Information Leak: Early Return
        }
    }
    return 1;
