// 2. SECURE: Constant-Time Comparison
// Iterates the ENTIRE string regardless of matches. Uses Bitwise XOR.
int secure_compare(const uint8_t *secret, const uint8_t *guess, size_t len) {
    uint8_t result = 0;

    for (size_t i = 0; i < len; i++) {
        // XOR returns 0 if bytes are identical, non-zero if different.
        // We accumulate the bits using OR.
        result |= (secret[i] ^ guess[i]);
    }

    // If result is still 0, all bytes matched perfectly.
    // We return 1 for success, 0 for failure, without a single 'if' branch.
    return (result == 0);
}
